    private fun handleLocalStorage(jsonObject: JSONObject) {
        val action = jsonObject.optString("action")
        val key = jsonObject.optString("key")
        val value = jsonObject.optString("value")

        when (action) {
            "setItem" -> {
                val prefs = context.getSharedPreferences("webapp_storage", Context.MODE_PRIVATE)
                prefs.edit().putString(key, value).apply()
            }
            "getItem" -> {
                val prefs = context.getSharedPreferences("webapp_storage", Context.MODE_PRIVATE)
                val result = prefs.getString(key, null)
                jsBridge.nativeCallback(jsonObject.optString("callbackId"), "\"$result\"")
            }
            "removeItem" -> {
                val prefs = context.getSharedPreferences("webapp_storage", Context.MODE_PRIVATE)
                prefs.edit().remove(key).apply()
            }
        }
    }

